#include <bits/stdc++.h>
#define x first
#define y second
using namespace std;

const int N=3e5+10;

struct Node{
    int u,d,l,r,k,id;
}qu[550];

int n,m,q,a[N],b[N],ans[N],son[N*32][2],tot=1;
vector<int> s[N*32];

bool cmp(Node x,Node y){
    return x.r<y.r;
}

void Add(int x){
    int p=1;
    for(int i=30;i>=0;i--){
        if(!son[p][(b[x]>>i)&1])
            son[p][(b[x]>>i)&1]=++tot;
        p=son[p][(b[x]>>i)&1];
        s[p].push_back(x);
    }
}

int cal(int p,int x){
	int l=0,r=s[p].size();
	while(l<r){
		int mid=l+r>>1;
		if(s[p][mid]>=x)
			r=mid;
		else
			l=mid+1; 
	}
	return s[p].size()-l;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<=m;i++)
        scanf("%d",&b[i]);
    scanf("%d",&q);
    for(int i=1;i<=q;i++){
        scanf("%d%d%d%d%d",&qu[i].u,&qu[i].d,&qu[i].l,&qu[i].r,&qu[i].k);
        qu[i].id=i;
    }
    sort(qu+1,qu+q+1,cmp);
    vector<pair<int,int>> v;
    for(int i=1,j=1;i<=q;i++){
        while(j<=qu[i].r)
            Add(j++);
        for(int j=qu[i].u;j<=qu[i].d;j++)
            v.push_back(make_pair(a[j],1));
        int res=0,f=qu[i].k,sum;
        for(int j=30;j>=0;j--){
            sum=0;
            for(int k=0;k<v.size();k++){
                if(v[k].y==0)
                    continue;
                int num=((v[k].x>>j)&1);
                sum+=cal(son[v[k].y][num^1],qu[i].l);
//                printf("%d %d\n",son[v[k].y][num^1],sum);
                if(sum>=f)
                    continue;
            }
//            printf("%d",sum);
            if(sum<f){
//            	printf(" 0\n");
                f-=sum;
                for(int k=0;k<v.size();k++){
                    if(v[k].y==0)
                        continue;
                    v[k].y=son[v[k].y][(v[k].x>>j)&1];
                }
            }else{
//            	printf(" 1\n");
                res+=(1<<j);
                for(int k=0;k<v.size();k++){
                    if(v[k].y==0)
                        continue;
                    v[k].y=son[v[k].y][((v[k].x>>j)&1)^1];
                }
            }
        }
//        puts("");
        ans[qu[i].id]=res;
        v.clear();
    }
    for(int i=1;i<=q;i++)
        printf("%d\n",ans[i]);
    return 0;
}
